parameters.jsCode:
// Extract data from Aggregate node
const input = $input.first().json;

// Extract the actual complaints array
const complaints = input.data || []; // <--- fixed here

// Helper functions
const getCount = (arr) => Array.isArray(arr) ? arr.length : 0;
const countBy = (arr, prop, value) => {
  if (!Array.isArray(arr)) return 0;
  return arr.filter(item => item && item[prop] === value).length;
};
const groupBy = (arr, prop) => {
  if (!Array.isArray(arr)) return {};
  return arr.reduce((acc, item) => {
    if (item && item[prop] != null) {
      const key = item[prop];
      acc[key] = (acc[key] || 0) + 1;
    }
    return acc;
  }, {});
};

// Calculate complaints stats
const stats = {
  total: getCount(complaints),
  pending: countBy(complaints, 'status', 'Pending'),
  resolved: countBy(complaints, 'status', 'Resolved'),
  lowPriority: countBy(complaints, 'priority', 'Low'),
  mediumPriority: countBy(complaints, 'priority', 'Medium'),
  highPriority: countBy(complaints, 'priority', 'High'),
  byCategory: groupBy(complaints, 'category'),
  byDepartment: groupBy(complaints, 'department_id')
};

// Return formatted complaints summary
return [{
  json: {
    summary: stats,
    data: complaints,
    timestamp: new Date().toISOString(),
    recordCount: getCount(complaints)
  }
}];

// Example simple IP-based rate limit (in-memory — not cluster safe)

const ip = $json.headers["x-forwarded-for"] || "unknown";

if (!global.rateLimit) {
  global.rateLimit = {};
}

const now = Date.now();
const windowMs = 60 * 1000; // 1 minute
const maxRequests = 10;

if (!global.rateLimit[ip]) {
  global.rateLimit[ip] = [];
}

// Remove old timestamps
global.rateLimit[ip] = global.rateLimit[ip].filter(
  timestamp => now - timestamp < windowMs
);

if (global.rateLimit[ip].length >= maxRequests) {
  throw new Error("RATE_LIMIT_EXCEEDED");
}

global.rateLimit[ip].push(now);

return $input.all();

